items";a:4:{i:0;a:3:{s:6:"number";s:2:"01";s:5:"title";s:41:"Fresh ingredients, layered with intention";s:4:"body";s:108:"Cage-free eggs, premium proteins, bright salsas, and queso-driven richness create a strong first impression.";}i:1;a:3:{s:6:"number";s:2:"02";s:5:"title";s:31:"Fast pickup without boring food";s:4:"body";s:112:"The site prioritizes order buttons, visible prices, and clear menu browsing so the path to checkout stays short.";}i:2;a:3:{s:6:"number";s:2:"03";s:5:"title";s:31:"Fast pickup without boring food";s:4:"body";s:112:"The site prioritizes order buttons, visible prices, and clear menu browsing so the path to checkout stays short.";}i:3;a:3:{s:6:"number";s:2:"04";s:5:"title";s:31:"Fast pickup without boring food";s:4:"body";s:112:"The site prioritizes order buttons, visible prices, and clear menu browsing so the path to checkout stays short.";}}}s:4:"menu";a:13:{s:7:"eyebrow";s:9:"FULL MENU";s:5:"title";s:51:"The full spread, presented like a house menu board.";s:4:"body";s:75:"Menu sections are powered from Menu Categories and Menu Items in WordPress.";s:4:"note";s:72:"Desktop uses the richer menu board layout. Mobile uses stacked sections.";s:18:"categoryFocusTitle";s:14:"Category focus";s:17:"categoryFocusBody";s:91:"Browse one category at a time for a cleaner, more premium menu interaction without clutter.";s:12:"itemCtaLabel";s:18:"Order this burrito";s:5:"image";s:92:"http://localhost:8080/wp-content/uploads/2026/03/Gemini_Generated_Image_iuxlswiuxlswiuxl.png";s:8:"imageAlt";s:33:"Frankie''s Breakfast Burritos menu";s:4:"ctas";a:0:{}s:8:"sections";a:0:{}s:10:"footerNote";s:50:"Open live ordering for modifiers and full details.";s:9:"footerCta";a:3:{s:5:"label";s:16:"Order with Toast";s:4:"href";s:9:"#location";s:7:"variant";s:7:"primary";}}s:5:"about";a:5:{s:7:"eyebrow";s:15:"ABOUT FRANKIE''S";s:5:"title";s:81:"A neighborhood breakfast burrito spot with enough craft to feel worth the detour.";s:10:"paragraphs";a:2:{i:0;s:65:"Use this section to tell the brand story in two short paragraphs.";i:1;s:58:"Keep the copy specific, local, and operationally credible.";}s:5:"image";s:93:"http://localhost:8080/wp-content/uploads/2026/03/item-1600000000102810433_1759808489.jpg.jpeg";s:5:"facts";a:2:{i:0;a:2:{s:5:"value";s:10:"Open daily";s:5:"label";s:12:"8 AM to 3 PM";}i:1;a:2:{s:5:"value";s:12:"Agoura Hills";s:5:"label";s:21:"Roadside Drive pickup";}}}s:5:"proof";a:5:{s:7:"eyebrow";s:12:"SOCIAL PROOF";s:5:"title";s:64:"Trust cues that reassure people before they commit to breakfast.";s:4:"body";s:89:"Testimonials are managed as their own content type so they can be reviewed independently.";s:15:"backgroundImage";s:58:"http://localhost:8080/wp-content/uploads/2026/03/home.jpeg";s:5:"items";a:6:{i:0;a:3:{s:5:"title";s:4:"Ajay";s:4:"body";s:162:"Absolutely loved the food! The burritos are packed with flavor and feel super fresh. You can really tell they care about quality. Definitely my go-to spot now!”";s:6:"source";s:0:"";}i:1;a:3:{s:5:"title";s:5:"rahul";s:4:"body";s:47:"the food is awesome and cool. love the burritos";s:6:"source";s:0:"";}i:2;a:3:{s:5:"title";s:10:"jayantilal";s:4:"body";s:47:"the food is awesome and cool. love the burritos";s:6:"source";s:0:"";}i:3;a:3:{s:5:"title";s:7:"Emma K.";s:4:"body";s:171:"I didn’t think a breakfast burrito could taste this good. Everything is fresh, perfectly seasoned, and wrapped just right. Frankie’s is my new go-to spot every weekend";s:6:"source";s:0:"";}i:4;a:3:{s:5:"title";s:7:"Jason M";s:4:"body";s:175:"Frankie’s Breakfast Burrito completely changed my mornings. The flavors are insane, the portions are huge, and it actually keeps me full till lunch. I’m officially hooked!";s:6:"source";s:0:"";}i:5;a:3:{s:5:"title";s:12:"mark specter";s:4:"body";s:98:""The flavors are simple, pure, and balanced... the burrito is still light feeling and not greasy."";s:6:"source";s:0:"";}}}s:8:"location";a:20:{s:7:"eyebrow";s:29:"LOCATION, HOURS, AND ORDERING";s:5:"title";s:50:"Easy to find. Easy to order. Easy to come back to.";s:4:"name";s:28:"Frankie''s Breakfast Burritos";s:7:"address";s:20:"28708 Roadside Drive";s:4:"city";s:12:"Agoura Hills";s:6:"region";s:2:"CA";s:10:"postalCode";s:5:"91301";s:7:"country";s:2:"US";s:5:"phone";s:12:"+18183181034";s:5:"hours";s:34:"Open daily from 8:00 AM to 3:00 PM";s:18:"openingHoursSchema";a:1:{i:0;s:17:"Mo-Su 08:00-15:00";}s:8:"ordering";s:67:"Pickup, delivery, catering, and gift cards all route through Toast.";s:8:"orderUrl";s:0:"";s:10:"primaryCta";a:3:{s:5:"label";s:12:"Order Online";s:4:"href";s:0:"";s:7:"variant";s:7:"primary";}s:12:"secondaryCta";a:3:{s:5:"label";s:10:"Call Store";s:4:"href";s:16:"tel:+18183181034";s:7:"variant";s:9:"secondary";}s:8:"mapTitle";s:24:"Map and storefront panel";s:7:"mapBody";s:65:"Responsive embed area with parking, pickup, and landmark context.";s:11:"mapEmbedUrl";s:154:"https://www.google.com/maps?q=Frankie%27s%20Breakfast%20Burritos%2C%2028708%20Roadside%20Drive%2C%20Agoura%20Hills%2C%20CA%2C%2091301%2C%20US&output=embed";s:12:"cateringText";s:77:"Need breakfast for a crew? Catering packs feed up to 10 with 48 hours notice.";s:11:"cateringCta";a:3:{s:5:"label";s:16:"Explore Catering";s:4:"href";s:0:"";s:7:"variant";s:5:"light";}}s:8:"finalCta";a:5:{s:7:"eyebrow";s:15:"READY TO ORDER?";s:5:"title";s:70:"Start with a signature burrito. Add the tots. Make the morning better.";s:4:"body";s:68:"Use this final section to push directly into the live ordering flow.";s:10:"primaryCta";a:3:{s:5:"label";s:9:"Order Now";s:4:"href";s:0:"";s:7:"variant";s:5:"light";}s:12:"secondaryCta";a:3:{s:5:"label";s:9:"View Menu";s:4:"href";s:5:"#menu";s:7:"variant";s:9:"secondary";}}s:6:"footer";a:6:{s:15:"navigateHeading";s:8:"Navigate";s:12:"visitHeading";s:5:"Visit";s:12:"orderHeading";s:16:"Order and Social";s:11:"description";s:75:"Breakfast burritos, frescas, and loaded sides served daily in Agoura Hills.";s:5:"visit";a:4:{i:0;s:20:"28708 Roadside Drive";i:1;s:22:"Agoura Hill