INSERT INTO `wp_options` VALUES (1383,'_transient_frnk_a6eac923e201e281f46ec6b24820a55b','a:20:{s:2:"id";i:30;s:4:"type";s:4:"post";s:5:"title";s:22:"Frankie&#8217;s secret";s:4:"slug";s:15:"frankies-secret";s:6:"status";s:7:"publish";s:3:"url";s:22:"/blog/frankies-secret/";s:9:"permalink";s:43:"http://localhost:8080/blog/frankies-secret/";s:7:"excerpt";s:378:"A burrito (English: /bəˈriːtoʊ/, Spanish: [buˈrito] ⓘ)[1] or burro[2] in Mexico is, historically, a regional name, among others, for what is known as a taco, a tortilla filled with food, in other parts of the country. The term burrito was regional, specifically from Guanajuato, Guerrero, Michoacán, San Luis Potosí, Sonora and Sinaloa, for&hellip;";s:7:"content";s:17918:"<p>A <b>burrito</b> (<span class="rt-commentedText nowrap"><span class="IPA-label IPA-label-small">English: </span><span class="IPA nopopups noexcerpt" lang="en-fonipa"><a title="Help:IPA/English" href="https://en.wikipedia.org/wiki/Help:IPA/English">/<span title="''b'' in ''buy''">b</span><span title="/ə/: ''a'' in ''about''">ə</span><span title="/ˈ/: primary stress follows">ˈ</span><span title="''r'' in ''rye''">r</span><span title="/iː/: ''ee'' in ''fleece''">iː</span><span title="''t'' in ''tie''">t</span><span title="/oʊ/: ''o'' in ''code''">oʊ</span>/</a></span></span>, <span class="IPA-label IPA-label-small">Spanish:</span> <span class="IPA nowrap" lang="es-Latn-fonipa"><a title="Help:IPA/Spanish" href="https://en.wikipedia.org/wiki/Help:IPA/Spanish">[buˈrito]</a></span> <span class="ext-phonos"><span id="ooui-php-1" class="noexcerpt ext-phonos-PhonosButton ext-phonos-PhonosButton-emptylabel oo-ui-widget oo-ui-widget-enabled oo-ui-buttonElement oo-ui-buttonElement-frameless oo-ui-iconElement oo-ui-buttonWidget" data-nosnippet="" data-ooui="{&quot;_&quot;:&quot;mw.Phonos.PhonosButton&quot;,&quot;href&quot;:&quot;\\/\\/upload.wikimedia.org\\/wikipedia\\/commons\\/transcoded\\/b\\/bd\\/Burritos.ogg\\/Burritos.ogg.mp3&quot;,&quot;rel&quot;:[&quot;nofollow&quot;],&quot;framed&quot;:false,&quot;icon&quot;:&quot;volumeUp&quot;,&quot;data&quot;:{&quot;ipa&quot;:&quot;&quot;,&quot;text&quot;:&quot;&quot;,&quot;lang&quot;:&quot;en&quot;,&quot;wikibase&quot;:&quot;&quot;,&quot;file&quot;:&quot;Burritos.ogg&quot;},&quot;classes&quot;:[&quot;noexcerpt&quot;,&quot;ext-phonos-PhonosButton&quot;,&quot;ext-phonos-PhonosButton-emptylabel&quot;]}"></span><sup class="ext-phonos-attribution noexcerpt navigation-not-searchable"><a title="File:Burritos.ogg" href="https://en.wikipedia.org/wiki/File:Burritos.ogg">ⓘ</a></sup></span>)<sup id="cite_ref-1" class="reference"><a href="https://en.wikipedia.org/wiki/Burrito#cite_note-1"><span class="cite-bracket">[</span>1<span class="cite-bracket">]</span></a></sup> or <b>burro</b><sup id="cite_ref-auto_2-0" class="reference"><a href="https://en.wikipedia.org/wiki/Burrito#cite_note-auto-2"><span class="cite-bracket">[</span>2<span class="cite-bracket">]</span></a></sup> in Mexico is, historically, a regional name, among others, for what is known as a <a title="Taco" href="https://en.wikipedia.org/wiki/Taco">taco</a>, a <a title="Tortilla" href="https://en.wikipedia.org/wiki/Tortilla">tortilla</a> filled with food, in other parts of the country. The term <i>burrito</i> was regional, specifically from <a title="Guanajuato" href="https://en.wikipedia.org/wiki/Guanajuato">Guanajuato</a>, <a title="Guerrero" href="https://en.wikipedia.org/wiki/Guerrero">Guerrero</a>, <a title="Michoacán" href="https://en.wikipedia.org/wiki/Michoac%C3%A1n">Michoacán</a>, <a title="San Luis Potosí" href="https://en.wikipedia.org/wiki/San_Luis_Potos%C3%AD">San Luis Potosí</a>, <a title="Sonora" href="https://en.wikipedia.org/wiki/Sonora">Sonora</a> and <a title="Sinaloa" href="https://en.wikipedia.org/wiki/Sinaloa">Sinaloa</a>, for what is known as a <i>taco</i> in Mexico City and surrounding areas, and <i>codzito</i> in <a title="Yucatán" href="https://en.wikipedia.org/wiki/Yucat%C3%A1n">Yucatán</a> and <a title="Quintana Roo" href="https://en.wikipedia.org/wiki/Quintana_Roo">Quintana Roo</a>.<sup id="cite_ref-3" class="reference"><a href="https://en.wikipedia.org/wiki/Burrito#cite_note-3"><span class="cite-bracket">[</span>3<span class="cite-bracket">]</span></a></sup><sup id="cite_ref-Diccionario_de_Mejicanismos_4-0" class="reference"><a href="https://en.wikipedia.org/wiki/Burrito#cite_note-Diccionario_de_Mejicanismos-4"><span class="cite-bracket">[</span>4<span class="cite-bracket">]</span></a></sup><sup id="cite_ref-Burrito_5-0" class="reference"><a href="https://en.wikipedia.org/wiki/Burrito#cite_note-Burrito-5"><span class="cite-bracket">[</span>5<span class="cite-bracket">]</span></a></sup> Due to the cultural influence of Mexico City, the term <i>taco</i> became the default, and the meaning of terms like <i>burrito</i> and <i>codzito</i> were forgotten, leading many people to create new meanings and folk histories.</p>\n<p>In modern times, it is considered by many as a different dish in <a title="Mexican cuisine" href="https://en.wikipedia.org/wiki/Mexican_cuisine">Mexican</a><sup id="cite_ref-6" class="reference"><a href="https://en.wikipedia.org/wiki/Burrito#cite_note-6"><span class="cite-bracket">[</span>6<span class="cite-bracket">]</span></a></sup> and <a class="mw-redirect" title="Tex-Mex cuisine" href="https://en.wikipedia.org/wiki/Tex-Mex_cuisine">Tex-Mex cuisine</a><sup id="cite_ref-7" class="reference"><a href="https://en.wikipedia.org/wiki/Burrito#cite_note-7"><span class="cite-bracket">[</span>7<span class="cite-bracket">]</span></a></sup> that took form in <a title="Ciudad Juárez" href="https://en.wikipedia.org/wiki/Ciudad_Ju%C3%A1rez">Ciudad Juárez</a>, consisting of a <a title="Flour tortilla" href="https://en.wikipedia.org/wiki/Flour_tortilla">flour tortilla</a> wrapped into a sealed cylindrical shape around various ingredients.<sup id="cite_ref-8" class="reference"><a href="https://en.wikipedia.org/wiki/Burrito#cite_note-8"><span class="cite-bracket">[</span>8<span class="cite-bracket">]</span></a></sup> In Central and Southern Mexico, burritos are still considered tacos, and are known as <i>tacos de harina</i> (&#8220;<a title="Wheat flour" href="https://en.wikipedia.org/wiki/Wheat_flour">wheat flour</a> tacos&#8221;).<sup id="cite_ref-Burrito_5-1" class="reference"><a href="https://en.wikipedia.org/wiki/Burrito#cite_note-Burrito-5"><span class="cite-bracket">[</span>5<span class="cite-bracket">]</span></a></sup> The tortilla is sometimes lightly grilled or steamed to soften it, make it more pliable, and allow it to adhere to itself. Burritos are often eaten by hand, as their tight wrapping keeps the ingredients together. Burritos can also be served &#8220;wet&#8221;; i.e., covered in a savory and spicy sauce, when they would be eaten with a fork and knife.</p>\n<p>Burritos are filled with savory ingredients, most often a meat such as beef, chicken, or pork, and often include other ingredients, such as rice, cooked beans (either whole or <a title="Refried beans" href="https://en.wikipedia.org/wiki/Refried_beans">refried</a>), vegetables, such as lettuce and tomatoes, cheese, and condiments such as <a class="mw-redirect" title="Salsa (sauce)" href="https://en.wikipedia.org/wiki/Salsa_(sauce)">salsa</a>, <a title="Pico de gallo" href="https://en.wikipedia.org/wiki/Pico_de_gallo">pico de gallo</a>, <a title="Guacamole" href="https://en.wikipedia.org/wiki/Guacamole">guacamole</a>, or <a title="Crema (dairy product)" href="https://en.wikipedia.org/wiki/Crema_(dairy_product)">crema</a>.</p>\n<p>Burritos are often contrasted in present times with similar dishes such as <a title="Taco" href="https://en.wikipedia.org/wiki/Taco">tacos</a>, in which a small hand-sized tortilla is folded in half around the ingredients rather than wrapped and sealed, or with <a title="Enchilada" href="https://en.wikipedia.org/wiki/Enchilada">enchiladas</a>, which use <a title="Masa" href="https://en.wikipedia.org/wiki/Masa">corn masa</a> tortillas and are covered in a savory sauce to be eaten with a fork and knife.</p>\n<div class="mw-heading mw-heading2">\n<h2 id="Etymology">Etymology</h2>\n</div>\n<p>The word <i>burrito</i> means &#8220;little donkey&#8221; in Spanish, the diminutive form of <i><a class="extiw" title="wikt:burro" href="https://en.wiktionary.org/wiki/burro">burro</a></i>, or &#8220;donkey&#8221;. Sonoran historian and politician, Horacio Sorbazo Díaz, explained that the term originated in <a title="Sonora" href="https://en.wikipedia.org/wiki/Sonora">Sonora</a> where some dubious taco stands would sell donkey meat instead of beef, and people, maliciously, began calling tacos &#8220;burritos&#8221; implying they were made with donkey meat.<sup id="cite_ref-9" class="reference"><a href="https://en.wikipedia.org/wiki/Burrito#cite_note-9"><span class="cite-bracket">[</span>9<span class="cite-bracket">]</span></a></sup> Another possible origin is that it derives from the tendency for burritos to contain a lot of different things similar to how a donkey would be able to carry a large burden.<sup id="cite_ref-Duggan_10-0" class="reference"><a href="https://en.wikipedia.org/wiki/Burrito#cite_note-Duggan-10"><span class="cite-bracket">[</span>10<span class="cite-bracket">]</span></a></sup> An additional possible origin could be due to their resemblance to a rolled up pack as typically carried by donkeys, making it an example of <a title="Synecdoche" href="https://en.wikipedia.org/wiki/Synecdoche">synecdoche</a>.</p>\n<div class="mw-heading mw-heading2">\n<h2 id="History">History</h2>\n</div>\n<p>Before the development of the modern burrito, the <a title="Maya civilization" href="https://en.wikipedia.org/wiki/Maya_civilization">Maya civilization</a> of Mexico used <a title="Corn tortilla" href="https://en.wikipedia.org/wiki/Corn_tortilla">corn tortillas</a> as early as 1500 BC to <a title="Wrap (food)" href="https://en.wikipedia.org/wiki/Wrap_(food)">wrap</a> foods, with fillings of <a title="Chili pepper" href="https://en.wikipedia.org/wiki/Chili_pepper">chili peppers</a>, tomatoes, mushrooms, <a class="mw-redirect" title="Squash (plant)" href="https://en.wikipedia.org/wiki/Squash_(plant)">squash</a>, and avocados.<sup id="cite_ref-Morales_11-0" class="reference"><a href="https://en.wikipedia.org/wiki/Burrito#cite_note-Morales-11"><span class="cite-bracket">[</span>11<span class="cite-bracket">]</span></a></sup> Historically, the <a class="mw-redirect" title="Puebloan peoples" href="https://en.wikipedia.org/wiki/Puebloan_peoples">Pueblo peoples</a> of the <a title="Southwestern United States" href="https://en.wikipedia.org/wiki/Southwestern_United_States">Southwestern US</a> also made tortillas filled with beans and meat sauce and prepared much like the modern burrito.<sup id="cite_ref-12" class="reference"><a href="https://en.wikipedia.org/wiki/Burrito#cite_note-12"><span class="cite-bracket">[</span>12<span class="cite-bracket">]</span></a></sup> But these preparations could also be said to be the origin of the simpler <a title="Taco" href="https://en.wikipedia.org/wiki/Taco">taco</a>, rather than the modern burrito.</p>\n<p>The precise origin of the modern burrito is not currently known, but there is evidence that in Mexico <i>burrito</i> was mainly another name, among others, for a <i>taco</i>, a rolled tortilla, whether corn or wheat, filled with meat or other ingredients. In the 1895 <span title="Spanish-language text"><i lang="es">Diccionario de Mejicanismos</i></span> by Feliz Ramos i Duarte, <i>burrito</i> was identified as the regional name given in the Mexican state of <a title="Guanajuato" href="https://en.wikipedia.org/wiki/Guanajuato">Guanajuato</a> to what is known as a <i>taco</i> in other regions:<sup id="cite_ref-Cumo2015_13-0" class="reference"><a href="https://en.wikipedia.org/wiki/Burrito#cite_note-Cumo2015-13"><span class="cite-bracket">[</span>13<span class="cite-bracket">]</span></a></sup><sup id="cite_ref-14" class="reference"><a href="https://en.wikipedia.org/wiki/Burrito#cite_note-14"><span class="cite-bracket">[</span>14<span class="cite-bracket">]</span></a></sup></p>\n<blockquote class="templatequote"><p><span title="Spanish-language text"><i lang="es">Burrito: Tortilla arrollada, con carne u otra cosa dentro, que en Yucatán llaman coçito, y en Cuernavaca y en Mexico, taco.</i></span></p>\n<p>Burrito: Rolled-up tortilla, with meat or other things inside, what in Yucatán is called a <span title="Spanish-language text"><i lang="es">coçito</i></span> and in Cuernavaca and Mexico [City] a <span title="Spanish-language text"><i lang="es">taco</i></span>.</p></blockquote>\n<div class="templatequotecite">\n<p>— Feliz Ramos i Duarte</p>\n</div>\n<p>Both, <i>Diccionario Agrícola Nacional</i> (1935) by the Mexican <i>Dirección General de Estadística</i><sup id="cite_ref-15" class="reference"><a href="https://en.wikipedia.org/wiki/Burrito#cite_note-15"><span class="cite-bracket">[</span>15<span class="cite-bracket">]</span></a></sup> and <i>Diccionario de Mejicanismos</i> (1959) by Mexican linguist and philologist <a title="Francisco J. Santamaría" href="https://en.wikipedia.org/wiki/Francisco_J._Santamar%C3%ADa">Francisco J. Santamaría</a>, identify <i>burrito</i> as another name for a <i>taco</i> in the state of <a title="Guerrero" href="https://en.wikipedia.org/wiki/Guerrero">Guerrero</a>, while in the State of <a title="Sinaloa" href="https://en.wikipedia.org/wiki/Sinaloa">Sinaloa</a> it is specifically a taco filled with salt:<sup id="cite_ref-Diccionario_de_Mejicanismos_4-1" class="reference"><a href="https://en.wikipedia.org/wiki/Burrito#cite_note-Diccionario_de_Mejicanismos-4"><span class="cite-bracket">[</span>4<span class="cite-bracket">]</span></a></sup></p>\n<blockquote class="templatequote"><p><span title="Spanish-language text"><i lang="es">En el Estado de Guerrero, taco, en el sentido de tortilla arrollada con comida adentro. En Yucatan le llaman coorto. En Sinaloa, taco de tortilla con sal.</i></span></p>\n<p>(In the State of Guerrero, taco, in the sense of a rolled-up tortilla with food inside. In Yucatan they call it <i>coorto</i>. In Sinaloa, a tortilla taco with salt.)</p></blockquote>\n<div class="templatequotecite">\n<p>— Francisco J. Santamaría</p>\n</div>\n<p>The Dictionary of Mexican Spanish (Diccionario del Español de México) by the <a class="mw-redirect" title="Colegio de México" href="https://en.wikipedia.org/wiki/Colegio_de_M%C3%A9xico">Colegio de México</a> also provides those definitions, stating that it is a regionalism from, both, the states of Guerrero and <a title="Michoacán" href="https://en.wikipedia.org/wiki/Michoac%C3%A1n">Michoacán</a> for <i>taco</i>; and also states that, in the state of <a title="Sinaloa" href="https://en.wikipedia.org/wiki/Sinaloa">Sinaloa</a>, it is a &#8220;<i>taco de sal</i>&#8221; (salt taco), a rolled corn tortilla with salt in it.<sup id="cite_ref-Burrito_5-2" class="reference"><a href="https://en.wikipedia.org/wiki/Burrito#cite_note-Burrito-5"><span class="cite-bracket">[</span>5<span class="cite-bracket">]</span></a></sup></p>\n<p>In <i>Vocabulario Sonorense</i> (1966), Sonoran writer, historian and politician, Horacio Sobarzo Díaz, states the same, writing that <i>burro</i> is another name for a taco, but argues that it&#8217;s a regionalism from Sonora and that it originated from the fact that in some places in that state, donkey meat was sold instead of beef:<sup id="cite_ref-auto_2-1" class="reference"><a href="https://en.wikipedia.org/wiki/Burrito#cite_note-auto-2"><span class="cite-bracket">[</span>2<span class="cite-bracket">]</span></a></sup></p>\n<blockquote class="templatequote"><p><span title="Spanish-language text"><i lang="es">Burro, s.m. Envoltorio de tortilla con carne o algún otro alimento, taco. Alude el vocablo a la carne de burro que ha sido apetecida por nuestros indígenas. La carne seca del vacuno es muy gustada en Sonora, y se ha observado en algunas ocasiones que, aprovechándose esta circunstancia, se trafique fraudulentamente con carne oreada de burro. Es de presumirse que en lugares donde se servían fritangas se &#8220;diera gato por liebre&#8221;, y aludiéndose a ello maliciosamente se denominara burro al taco.</i></span></p>\n<p>(Burro, s.m. A tortilla wrap with meat or some other food, taco. The word alludes to donkey meat that has been enjoyed by our indigenous people. Dried beef is very popular in Sonora, and it has been observed on some occasions that, taking advantage of this circumstance, dried donkey meat is fraudulently sold. It is presumed that in places where fried foods were served, a &#8220;bait and switch&#8221; was done, and alluding to this maliciously, the taco was called <i>burro</i> (donkey).)</p></blockquote>\n<div class="templatequotecite">\n<p>— Horacio Sobarzo Díaz</p>\n</div>\n<p>In her book <i><a title="Life in Mexico" href="https://en.wikipedia.org/wiki/Life_in_Mexico">Life in Mexico</a></i> (1843) Scottish noblewoman <a title="Frances Erskine Inglis" href="https://en.wikipedia.org/wiki/Frances_Erskine_Inglis">Frances Erskine Inglis</a> writes that she ate <i>burros</i>, tortillas filled, in this case, with cheese, while on the road in <a title="Michoacán" href="https://en.wikipedia.org/wiki/Michoac%C3%A1n">Michoacán</a>:<sup id="cite_ref-16" class="reference"><a href="https://en.wikipedia.org/wiki/Burrito#cite_note-16"><span class="cite-bracket">[</span>16<span class="cite-bracket">]</span></a></sup></p>\n<blockquote class="templatequote"><p>&#8230; the gentlemen from Morelia, suffering for their politeness in having escorted us, the two damsels of the bath, naiads of the boiling spring, pitying our hungry condition, came to offer their services; one asked me if I should like &#8220;to eat a burro in the mean time&#8221;? A burro being an ass, I was rather startled at the proposition, and assured her that I should infinitely prefer waiting a little longer before resorting to so desperate a measure. &#8220;Some people call them pecadoras&#8221;, (female sinners!) said her sister. Upon this, the gentlemen came to our assistance, and <i>burros</i> or <i>pecadoras</i> were ordered forthwith. They proved to be hot tortillas, with cheese in them, and we found them particularly good.</p></blockquote>\n<p>Being that <i>burrito</i> or <i>burro</i> was originally a regional name for what is known as a <i>taco</i> or <i>codzito</i> in other regions of Mexico, the use of both corn and wheat flour tortillas</p>\n";s:13:"featuredImage";s:0:"";s:16:"featuredImageAlt";s:22:"Frankie&#8217;s secret";s:11:"publishedAt";s:25:"2026-03-24T21:10:59+00:00";s:10:"modifiedAt";s:25:"2026-03-24T21:10:59+00:00";s:6:"author";a:3:{s:2:"id";i:1;s:4:"name";s:5:"admin";s:4:"slug";s:5:"admin";}s:18:"readingTimeMinutes";i:7;s:10:"categories";a:1:{i:0;a:3:{s:2:"id";i:1;s:4:"name";s:13:"Uncategorized";s:4:"slug";s:13:"uncategorized";}}s:4:"tags";a:0:{}s:3:"seo";a:8:{s:5:"title";s:43:"Frankie&#8217;s secret | Frankie''s Burritos";s:11:"description";s:91:"Fire-grilled breakfast burritos in Agoura Hills with pickup, catering, and online ordering.";s:12:"canonicalUrl";s:43:"http://localhost:8080/blog/frankies-secret/";s:7:"ogImage";s:0:"";s:8:"keywords";s:118:"Uncategorized, Frankie&#8217;s secret, breakfast burritos agoura hills, frankies breakfast burritos, breakfast near me";s:7:"noindex";b:0;s:11:"twitterCard";s:19:"summary_large_image";s:6:"schema";a:2:{s:8:"@context";s:18:"https://schema.org";s:6:"@graph";a:2:{i:0;a:2:{s:5:"@type";s:14:"BreadcrumbList";s:15:"itemListElement";a:3:{i:0;a:4:{s:5:"@type";s:8:"ListItem";s:8:"position";i:1;s:4:"name";s:4:"Home";s:4:"item";s:22:"http://localhost:8080/";}i:1;a:4:{s:5:"@type";s:8:"ListItem";s:8:"position";i:2;s:4:"name";s:7:"Journal";s:4:"item";s:27:"http://localhost:8080/blog/";}i:2;a:4:{s:5:"@type";s:8:"ListItem";s:8:"position";i:3;s:4:"name";s:22:"Frankie&#8217;s secret";s:4:"item";s:43:"http://localhost:8080/blog/frankies-secret/";}}}i:1