image";s:0:"";s:12:"dateModified";s:25:"2026-03-24T20:27:38+00:00";}}}}}s:7:"related";a:1:{i:0;a:17:{s:2:"id";i:1;s:4:"type";s:4:"post";s:5:"title";s:12:"Hello world!";s:4:"slug";s:11:"hello-world";s:6:"status";s:7:"publish";s:3:"url";s:18:"/blog/hello-world/";s:9:"permalink";s:39:"http://localhost:8080/blog/hello-world/";s:7:"excerpt";s:85:"Welcome to WordPress. This is your first post. Edit or delete it, then start writing!";s:13:"featuredImage";s:0:"";s:16:"featuredImageAlt";s:12:"Hello world!";s:11:"publishedAt";s:25:"2026-03-21T20:20:36+00:00";s:10:"modifiedAt";s:25:"2026-03-21T20:20:36+00:00";s:6:"author";a:3:{s:2:"id";i:1;s:4:"name";s:5:"admin";s:4:"slug";s:5:"admin";}s:18:"readingTimeMinutes";i:1;s:10:"categories";a:1:{i:0;a:3:{s:2:"id";i:1;s:4:"name";s:13:"Uncategorized";s:4:"slug";s:13:"uncategorized";}}s:4:"tags";a:0:{}s:3:"seo";a:8:{s:5:"title";s:33:"Hello world! | Frankie''s Burritos";s:11:"description";s:91:"Fire-grilled breakfast burritos in Agoura Hills with pickup, catering, and online ordering.";s:12:"canonicalUrl";s:39:"http://localhost:8080/blog/hello-world/";s:7:"ogImage";s:0:"";s:8:"keywords";s:108:"Uncategorized, Hello world!, breakfast burritos agoura hills, frankies breakfast burritos, breakfast near me";s:7:"noindex";b:0;s:11:"twitterCard";s:19:"summary_large_image";s:6:"schema";a:2:{s:8:"@context";s:18:"https://schema.org";s:6:"@graph";a:2:{i:0;a:2:{s:5:"@type";s:14:"BreadcrumbList";s:15:"itemListElement";a:3:{i:0;a:4:{s:5:"@type";s:8:"ListItem";s:8:"position";i:1;s:4:"name";s:4:"Home";s:4:"item";s:22:"http://localhost:8080/";}i:1;a:4:{s:5:"@type";s:8:"ListItem";s:8:"position";i:2;s:4:"name";s:7:"Journal";s:4:"item";s:27:"http://localhost:8080/blog/";}i:2;a:4:{s:5:"@type";s:8:"ListItem";s:8:"position";i:3;s:4:"name";s:12:"Hello world!";s:4:"item";s:39:"http://localhost:8080/blog/hello-world/";}}}i:1;a:9:{s:5:"@type";s:11:"BlogPosting";s:3:"@id";s:47:"http://localhost:8080/blog/hello-world/#article";s:16:"mainEntityOfPage";s:39:"http://loca