eet us</a></div><!-- /wp:button --></div>\n<!-- /wp:buttons --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class="wp-block-column"><!-- wp:image {"id":304,"aspectRatio":"3/4","scale":"cover","sizeSlug":"full","linkDestination":"none"} -->\n<figure class="wp-block-image size-full"><img src="https://s2.wp.com/i/woo-block-patterns/2024/07/54f708281f82831c082a1cf9d7b7faa9-1.jpeg" alt="" class="wp-image-304" style="aspect-ratio:3/4;object-fit:cover"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->\n\n<!-- wp:spacer {"height":"calc( 0.25 * var(\\u002d\\u002dwp\\u002d\\u002dstyle\\u002d\\u002droot\\u002d\\u002dpadding-right, var(\\u002d\\u002dwp\\u002d\\u002dcustom\\u002d\\u002dgap\\u002d\\u002dhorizontal)))"} -->\n<div style="height:calc( 0.25 * var(--wp--style--root--padding-right, var(--wp--custom--gap--horizontal)))" aria-hidden="true" class="wp-block-spacer"></div>\n<!-- /wp:spacer --></div>\n<!-- /wp:group -->";s:14:"disallow_after";a:0:{}s:12:"dependencies";a:0:{}s:10:"categories";a:1:{s:22:"_dotcom_imported_about";a:3:{s:4:"slug";s:22:"_dotcom_imported_about";s:5:"title";s:22:"_dotcom_imported_about";s:11:"description";s:0:"";}}s:13:"subcategories";a:0:{}s:24:"virtual_theme_categories";a:0:{}s:4:"tags";a:0:{}s:12:"pattern_meta";a:0:{}s:10:"source_url";s:83:"https://wooblockpatterns.wpcomstaging.com/2024/07/01/tall-content-with-image-right/";s:13:"modified_date";s:19:"2024-07-01 15:58:41";s:12:"preview_data";a:0:{}s:23:"pattern_design_metadata";a:7:{s:9:"alignment";a:0:{}s:12:"text_density";a:0:{}s:13:"media_density";a:0:{}s:11:"personality";a:0:{}s:14:"next_alignment";a:0:{}s:17:"next_text_density";a:0:{}s:18:"next_media_density";a:0:{}}s:9:"post_type";s:8:"wp_block";s:22:"is_included_in_big_sky";i:0;}i:33;a:20:{s:2:"ID";i:301;s:7:"site_id";i:231214916;s:5:"title";s:24:"Spread right, heavy text";s:4:"name";s:23:"spread-right-heavy-text";s:11:"description";s:0:"";s:1