":"0","bottom":"0"}}},"layout":{"type":"constrained","justifyContent":"center"}} -->\n<div class="wp-block-group alignfull" style="margin-top:0;margin-bottom:0;padding-top:calc( 0.5 * var(--wp--style--root--padding-right, var(--wp--custom--gap--horizontal)));padding-right:var(--wp--style--root--padding-right, var(--wp--custom--gap--horizontal));padding-bottom:calc( 0.5 * var(--wp--style--root--padding-right, var(--wp--custom--gap--horizontal)));padding-left:var(--wp--style--root--padding-left, var(--wp--custom--gap--horizontal))"><!-- wp:spacer {"height":"calc( 0.25 * var(\\u002d\\u002dwp\\u002d\\u002dstyle\\u002d\\u002droot\\u002d\\u002dpadding-right, var(\\u002d\\u002dwp\\u002d\\u002dcustom\\u002d\\u002dgap\\u002d\\u002dhorizontal)))"} -->\n<div style="height:calc( 0.25 * var(--wp--style--root--padding-right, var(--wp--custom--gap--horizontal)))" aria-hidden="true" class="wp-block-spacer"></div>\n<!-- /wp:spacer -->\n\n<!-- wp:columns {"verticalAlignment":"center","align":"wide"} -->\n<div class="wp-block-columns alignwide are-vertically-aligned-center"><!-- wp:column {"width":"50%"} -->\n<div class="wp-block-column" style="flex-basis:50%"><!-- wp:heading {"textAlign":"left","fontSize":"x-large"} -->\n<h2 class="wp-block-heading has-text-align-left has-x-large-font-size">Discover a world of possibilities</h2>\n<!-- /wp:heading -->\n\n<!-- wp:spacer {"height":"8px"} -->\n<div style="height:8px" aria-hidden="true" class="wp-block-spacer"></div>\n<!-- /wp:spacer -->\n\n<!-- wp:buttons {"layout":{"type":"flex","justifyContent":"left"}} -->\n<div class="wp-block-buttons"><!-- wp:button --><div class="wp-block-button"><a class="wp-block-button__link wp-element-button">Get Started</a></div><!-- /wp:button --></div>\n<!-- /wp:buttons --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {"width":"50%"} -->\n<div class="wp-block-column" style="flex-basis:50%"><!-- wp:paragraph {"style":{"layout":{"selfStretch":"fixed","flexSize":"70%"}}} -->\n<p>We believe that your home should be a reflection of your unique style and personality. Our curated collection of home essentials and decor pieces is designed to help you create a space that feels truly like you.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {"style":{"layout":{"selfStretch":"fixed","flexSize":"70%"}}} -->\n<p>Our expert designers will work closely with you to bring your vision to life. From furniture selection to color schemes, we''ll provide professional advice and guidance every step of the way to help you achieve the perfect balance of comfort, functionality, and aesthetic appeal.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->\n\n<!-- wp:spacer {"height":"calc( 0.25 * var(\\u002d\\u002dwp\\u002d\\u002dstyle\\u002d\\u002droot\\u002d\\u002dpadding-right, var(\\u002d\\u002dwp\\u002d\\u002dcustom\\u002d\\u002dgap\\u002d\\u002dhorizontal)))"} -->\n<div style="height:calc( 0.25 * var(--wp--style--root--padding-right, var(--wp--custom--gap--horizontal)))" aria-hidden="true" class="wp-block-spacer"></div>\n<!-- /wp:spacer --></div>\n<!-- /wp:group -->";s:14:"disallow_after";a:0:{}s:12:"dependencies";a:0:{}s:10:"categories";a:1:{s:22:"_dotcom_imported_about";a:3:{s:4:"slug";s:22:"_dotcom_imported_about";s:5:"title";s:22:"_dotcom_imported_about";s:11:"description";s:0:"";}}s:13:"subcategories";a:0:{}s:24:"virtual_theme_categories";a:0:{}s:4:"tags";a:0:{}s:12:"pattern_meta";a:0:{}s:10:"source_url";s:82:"https://wooblockpatterns.wpcomstaging.com/2024/07/01/heading-with-button-and-text/";s:13:"modified_date";s:19:"2024-07-01 15:56:19";s:12:"preview_data";a:0:{}s:23:"pattern_design_metadata";a:7:{s:9:"alignment";a:0:{}s:12:"text_density";a:0:{}s:13:"media_density";a:0:{}s:11:"personality";a:0:{}s:14:"next_alignment";a:0:{}s:17:"next_text_density";a:0:{}s:18:"next_media_density";a:0:{}}s:9:"post_type";s:8:"wp_block";s:22:"is_included_in_big_sky";i:0;}i:35;a:20:{s:2:"ID";i:297;s:7:"site_id";i:231214916;s:5:"title";s:20:"Left-aligned content";s:4:"name";s: