-vintage-wheel-retro-old.jpg" alt="" class="wp-image-70"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:spacer {"height":"calc( 0.25 * var(\\u002d\\u002dwp\\u002d\\u002dstyle\\u002d\\u002droot\\u002d\\u002dpadding-right, var(\\u002d\\u002dwp\\u002d\\u002dcustom\\u002d\\u002dgap\\u002d\\u002dhorizontal)))"} -->\n<div style="height:calc( 0.25 * var(--wp--style--root--padding-right, var(--wp--custom--gap--horizontal)))" aria-hidden="true" class="wp-block-spacer"></div>\n<!-- /wp:spacer --></div>\n<!-- /wp:group -->";s:14:"disallow_after";a:0:{}s:12:"dependencies";a:0:{}s:10:"categories";a:1:{s:22:"_dotcom_imported_intro";a:3:{s:4:"slug";s:22:"_dotcom_imported_intro";s:5:"title";s:22:"_dotcom_imported_intro";s:11:"description";s:0:"";}}s:13:"subcategories";a:0:{}s:24:"virtual_theme_categories";a:0:{}s:4:"tags";a:0:{}s:12:"pattern_meta";a:0:{}s:10:"source_url";s:86:"https://wooblockpatterns.wpcomstaging.com/2024/07/01/pull-right-with-wide-image-below/";s:13:"modified_date";s:19:"2024-07-01 15:17:04";s:12:"preview_data";a:0:{}s:23:"pattern_design_metadata";a:7:{s:9:"alignment";a:0:{}s:12:"text_density";a:0:{}s:13:"media_density";a:0:{}s:11:"personality";a:0:{}s:14:"next_alignment";a:0:{}s:17:"next_text_density";a:0:{}s:18:"next_media_density";a:0:{}}s:9:"post_type";s:8:"wp_block";s:22:"is_included_in_big_sky";i:0;}i:51;a:20:{s:2:"ID";i:249;s:7:"site_id";i:231214916;s:5:"title";s:39:"Fullwidth image with content and button";s:4:"name";s:39:"fullwidth-image-with-content-and-button";s:11:"description";s:0:"";s:14:"ai_description";s:0:"";s:4:"html";s:3735:"<!-- wp:group {"metadata":{"name":"Intro","categories":["intro"],"patternName":"a8c/intro-fullwidth-image-with-content-and-button-2"},"align":"full","style":{"spacing":{"padding":{"top":"0","bottom":"calc( 0.5 * var(\\u002d\\u002dwp\\u002d\\u002dstyle\\u002d\\u002droot\\u002d\\u002dpadding-right, var(\\u002d\\u002dwp\\u002d\\u002dcustom\\u002d\\u002dgap\\u002d\\u002dhorizontal)))","left":"var(\\u002d\\u002dwp\\u002d\\u002dstyle\