INSERT INTO `wp_options` VALUES (1755,'_transient_frnk_a9996dd05874e78b9c80b07fa18d752e','a:5:{s:7:"content";a:17:{s:12:"announcement";s:77:"Fresh breakfast burritos made daily in Agoura Hills. Order online for pickup.";s:8:"siteName";s:18:"Frankie''s Burritos";s:11:"siteTagline";s:21:"Can you smell it more";s:8:"siteLogo";s:109:"http://localhost:8080/wp-content/uploads/2026/03/WhatsApp_Image_2026-03-19_at_23.18.30-removebg-preview-1.png";s:13:"siteLogoLight";s:109:"http://localhost:8080/wp-content/uploads/2026/03/Gemini_Generated_Image_iyropxiyropxiyro-removebg-preview.png";s:11:"siteLogoAlt";s:18:"Frankie''s Burritos";s:4:"hero";a:5:{s:5:"title";s:18:"Frankie''s burritos";s:15:"backgroundImage";s:58:"http://localhost:8080/wp-content/uploads/2026/03/home.jpeg";s:11:"mobileImage";s:58:"http://localhost:8080/wp-content/uploads/2026/03/home.jpeg";s:10:"primaryCta";a:3:{s:5:"label";s:12:"Order Online";s:4:"href";s:45:"https://frankiesbreakfastburritos.toast.site/";s:7:"variant";s:7:"primary";}s:12:"secondaryCta";a:3:{s:5:"label";s:9:"View Menu";s:4:"href";s:5:"#menu";s:7:"variant";s:9:"secondary";}}s:10:"navigation";a:5:{i:0;a:2:{s:5:"label";s:4:"Home";s:4:"href";s:4:"#top";}i:1;a:2:{s:5:"label";s:4:"Menu";s:4:"href";s:5:"#menu";}i:2;a:2:{s:5:"label";s:4:"Blog";s:4:"href";s:6:"/blog/";}i:3;a:2:{s:5:"label";s:5:"About";s:4:"href";s:6:"#about";}i:4;a:2:{s:5:"label";s:8:"Location";s:4:"href";s:9:"#location";}}s:13:"featuredIntro";a:3:{s:7:"eyebrow";s:17:"FEATURED BURRITOS";s:5:"title";s:43:"The burritos people will open the site for.";s:3:"cta";a:3:{s:5:"label";s:13:"See Full Menu";s:4:"href";s:5:"#menu";s:7:"variant";s:7:"primary";}}s:13:"featuredItems";a:0:{}s:7:"reasons";a:4:{s:7:"eyebrow";s:25:"WHY PEOPLE LOVE FRANKIE''S";s:5:"title";s:79:"Built like a neighborhood favorite, presented like a premium fast-casual brand.";s:4:"body";s:126:"Every highlight below reinforces appetite, trust, and speed so the site feels handcrafted without slowing down the order path.";s:5:"