 currently support. We recommend EU/UK VAT Validation Manager for WooCommerce as a replacement";}}s:7:"actions";a:1:{i:0;O:8:"stdClass":6:{s:4:"name";s:31:"uk-vat-notice-button-2025-04-30";s:7:"locales";a:1:{i:0;O:8:"stdClass":2:{s:6:"locale";s:5:"en_US";s:5:"label";s:31:"Learn more about this extension";}}s:3:"url";s:53:"https://wordpress.org/plugins/eu-vat-for-woocommerce/";s:18:"url_is_admin_query";b:0;s:10:"is_primary";b:0;s:6:"status";s:8:"actioned";}}s:5:"rules";a:3:{i:0;O:8:"stdClass":2:{s:4:"type";s:17:"plugins_activated";s:7:"plugins";a:1:{i:0;s:25:"woocommerce-eu-vat-number";}}i:1;O:8:"stdClass":2:{s:4:"type";s:18:"publish_after_time";s:13:"publish_after";s:19:"2025-05-05 00:00:00";}i:2;O:8:"stdClass":2:{s:4:"type";s:19:"publish_before_time";s:14:"publish_before";s:19:"2025-05-15 00:00:00";}}}s:44:"paypal-braintree-sdk-depreciation-2025-05-30";O:8:"stdClass":8:{s:4:"slug";s:44:"paypal-braintree-sdk-depreciation-2025-05-30";s:4:"type";s:6:"update";s:6:"status";s:10:"unactioned";s:12:"is_snoozable";i:0;s:6:"source";s:15:"woocommerce.com";s:7:"locales";a:1:{i:0;O:8:"stdClass":3:{s:6:"locale";s:5:"en_US";s:5:"title";s:54:"Action required: Update the PayPal Braintree extension";s:7:"content";s:228:"Your PayPal Braintree extension is using an outdated SDK and will stop processing payments after June 30, 2025, due to a root SSL certificate expiration. To avoid service disruption, update to version 3.2.4 or newer immediately.";}}s:7:"actions";a:1:{i:0;O:8:"stdClass":6:{s:4:"name";s:51:"paypal-braintree-sdk-depreciation-2025-05-30-button";s:7:"locales";a:1:{i:0;O:8:"stdClass":2:{s:6:"locale";s:5:"en_US";s:5:"label";s:10:"Update now";}}s:3:"url";s:21:"/wp-admin/plugins.php";s:18:"url_is_admin_query";b:1;s:10:"is_primary";b:1;s:6:"status";s:10:"unactioned";}}s:5:"rules";a:2:{i:0;O:8:"stdClass":2:{s:4:"type";s:18:"publish_after_time";s:13:"publish_after";s:19:"2025-05-29 17:56:45";}i:1;O:8:"stdClass":4:{s:4:"type";s:14:"plugin_version";s:6:"plugin";s:47:"woocommerce-g